{
  "episode_number": 4,
  "title": "人设崩了",
  "scenes": [
    {
      "scene_number": 1,
      "location": "小洋楼·二楼男生卧室",
      "time_of_day": "午后",
      "atmosphere": "紧张不安，即将面临考验的压迫感",
      "weather": "午后阳光透过窗帘洒入",
      "sfx_ambient": "远处女生们的轻声聊天、衣柜关门声",
      "initial_shot": "【近景】承接上集——导演站在卧室门口，表情严肃",
      "characters": ["沈央", "宿寒英"],
      "content": [
        {
          "type": "action",
          "text": "【近景】导演站在门口，面容严肃如同中学教导主任。沈央悄悄把内裤盒塞到宿寒英手里，手心冒汗。"
        },
        {
          "type": "dialogue",
          "character": "沈央",
          "emotion": "努力镇定",
          "text": "差不多好了。"
        },
        {
          "type": "action",
          "text": "【近景】导演扫了一眼卧室，点点头——"
        },
        {
          "type": "dialogue",
          "character": "沈央",
          "emotion": "转述导演的话",
          "text": ""
        },
        {
          "type": "action",
          "text": "【中景】导演说准备录单采，其他人都已经录好了。"
        },
        {
          "type": "inner_voice",
          "character": "沈央",
          "emotion": "紧张",
          "text": "单采……在镜头前一个人面对一堆设备说话。比面对摄像机更可怕的来了。"
        },
        {
          "type": "action",
          "text": "【特写】沈央不自觉地吞了口唾沫，喉结微微滚动。"
        },
        {
          "type": "action",
          "text": "【近景】导演看看沈央又看看宿寒英，问谁先来。沈央不知所措地转头看向宿寒英——"
        },
        {
          "type": "action",
          "text": "【近景】宿寒英从容地关上衣柜门，语气平静——"
        },
        {
          "type": "dialogue",
          "character": "宿寒英",
          "emotion": "平静自然",
          "text": "他先去。"
        },
        {
          "type": "action",
          "text": "【特写】沈央愣了一下，嘴唇动了动想说什么，但最终只是认命般地点了头。"
        },
        {
          "type": "inner_voice",
          "character": "沈央",
          "emotion": "无奈又庆幸",
          "text": "丝毫没有反抗精神……但居然松了口气？至少不用自己做选择了。"
        },
        {
          "type": "dialogue",
          "character": "沈央",
          "emotion": "温驯",
          "text": "……好。"
        },
        {
          "type": "action",
          "text": "【中景·跟拍】沈央跟着导演走出卧室，最后回头看了一眼——宿寒英正靠在衣柜旁，冲他微微抬了下下巴，像是在说'去吧'。"
        }
      ]
    },
    {
      "scene_number": 2,
      "location": "小洋楼·单采室",
      "time_of_day": "午后",
      "atmosphere": "压迫紧张的采访环境，沈央的社恐全面爆发，笑料密集",
      "weather": "室内人工灯光，明亮偏白",
      "sfx_ambient": "摄影设备的微弱嗡鸣、灯光的电流声",
      "initial_shot": "【全景】小型采访间，一把空椅子面对密集的摄影设备，灯光明亮刺眼",
      "characters": ["沈央"],
      "content": [
        {
          "type": "action",
          "text": "【全景】单采室。一把椅子面对密集的摄影设备和灯光阵列，纯色幕布背景。设备后方站着导演和几位工作人员。"
        },
        {
          "type": "action",
          "text": "【中景】沈央走进来，面对这阵仗——浑身肌肉微微绷紧。他僵硬地走到椅子前坐下，双手放在膝盖上，后背挺得笔直。"
        },
        {
          "type": "inner_voice",
          "character": "沈央",
          "emotion": "极度紧张",
          "text": "密集的设备、密集的人头……有种罪犯面临审问的荒诞感。"
        },
        {
          "type": "action",
          "text": "【近景】导演在设备后方说——'别紧张，随便介绍下自己，说说你对恋爱的看法，为什么来这个节目，自由发挥。'"
        },
        {
          "type": "action",
          "text": "【特写】沈央深吸一口气，胸腔明显起伏。他理了理衣领——那个标志性的紧张动作。"
        },
        {
          "type": "action",
          "text": "【近景】导演喊——'OK，开始。'"
        },
        {
          "type": "action",
          "text": "【近景】沈央挤出一个僵硬的笑容，挺直腰板，突然用一口标准的朗诵腔——"
        },
        {
          "type": "dialogue",
          "character": "沈央",
          "emotion": "一本正经朗诵腔",
          "text": "观众朋友们大家好！我是嘉宾沈央，沈是三点水——"
        },
        {
          "type": "sound",
          "text": "音效：刹车声'吱——'"
        },
        {
          "type": "action",
          "text": "【近景】导演皱眉打断——"
        },
        {
          "type": "action",
          "text": "【中景】导演说这段播出时会给字幕，不用说那么具体，放松点儿。见沈央茫然眨眼，导演隐隐头疼——'算了，你随便说。'"
        },
        {
          "type": "action",
          "text": "【特写】沈央的笑容碎了一角，眼底闪过一丝窘迫。他抿了抿嘴，重振旗鼓——"
        },
        {
          "type": "effect",
          "text": "【特效】屏幕左上角浮现：「第二次尝试」"
        },
        {
          "type": "dialogue",
          "character": "沈央",
          "emotion": "重新鼓起勇气",
          "text": "电视机前的朋友们——"
        },
        {
          "type": "sound",
          "text": "音效：错误提示音'嘟——'"
        },
        {
          "type": "action",
          "text": "【近景】导演面无表情——'我们是网播。'"
        },
        {
          "type": "action",
          "text": "【特写】沈央的嘴僵在半张的状态，两秒后缓缓闭上。他的耳根开始泛红。"
        },
        {
          "type": "inner_voice",
          "character": "沈央",
          "emotion": "痛苦",
          "text": "……网播。对。没有电视机。"
        },
        {
          "type": "effect",
          "text": "【特效】屏幕左上角浮现：「第三次尝试」"
        },
        {
          "type": "action",
          "text": "【近景】沈央深深吸了口气，双手握拳放在膝盖上，重新开口。这一次他的语速放慢了，表情也终于自然了一些——"
        },
        {
          "type": "dialogue",
          "character": "沈央",
          "emotion": "终于放松一些",
          "text": "朋友们好，我叫沈央。"
        },
        {
          "type": "dialogue",
          "character": "沈央",
          "emotion": "渐入状态",
          "text": "很高兴参加《心动28天》这档综艺。"
        },
        {
          "type": "dialogue",
          "character": "沈央",
          "emotion": "真诚坦白",
          "text": "在来节目之前我曾经犹豫过，因为我的性格比较内向，不擅长与陌生人——"
        },
        {
          "type": "sound",
          "text": "音效：急刹车'吱——！'"
        },
        {
          "type": "action",
          "text": "【近景】导演猛地抬手——"
        },
        {
          "type": "effect",
          "text": "【特效·震动】画面轻微震动，屏幕中央弹出大字——"
        },
        {
          "type": "action",
          "text": "【中景】导演的声音响彻单采室——'停！人设崩了！'"
        },
        {
          "type": "sound",
          "text": "音效：玻璃碎裂声'哐啷——'"
        },
        {
          "type": "action",
          "text": "【特写】沈央的表情定格——嘴角微张，眼睛缓缓眨了一下，瞳孔里映出采访灯刺眼的白光。他的嘴角在笑与不笑之间微妙地颤了颤。"
        },
        {
          "type": "inner_voice",
          "character": "沈央",
          "emotion": "灵魂出窍的沮丧",
          "text": "一鼓作气势如虎……再而衰……三而竭。人设崩了。中央空调人设，崩了。"
        },
        {
          "type": "action",
          "text": "【中景·拉镜头】沈央一个人坐在采访椅上，四周密集的设备和灯光包围着他。他低下头，双手撑在膝盖上，肩膀微微垮了下来。"
        },
        {
          "type": "sound",
          "text": "BGM：轻柔但略带感伤的吉他拨弦"
        },
        {
          "type": "effect",
          "text": "【淡出】单采室画面缓缓淡出"
        }
      ]
    },
    {
      "scene_number": 3,
      "location": "小洋楼·二楼男生卧室",
      "time_of_day": "黄昏",
      "atmosphere": "沮丧后的安静，被温暖治愈的微光时刻",
      "weather": "黄昏暖橘色光线从窗口洒入",
      "sfx_ambient": "远处鸟鸣渐稀、黄昏的安静",
      "initial_shot": "【全景】黄昏光线穿过窗户，在蓝色卧室的地板上投下暖橘色长条光斑",
      "characters": ["沈央", "宿寒英"],
      "content": [
        {
          "type": "action",
          "text": "【全景】黄昏的光从窗户斜射进来，蓝色卧室的地板上投下暖橘色的光斑。楼道里很安静。"
        },
        {
          "type": "action",
          "text": "【中景】沈央独自坐在二楼楼道的台阶上，双臂环抱膝盖，脑袋微微低着，刘海遮住了半边眼睛。"
        },
        {
          "type": "inner_voice",
          "character": "沈央",
          "emotion": "丧",
          "text": "通告费……要对得起通告费。但我连单采都搞不定，后面二十八天怎么熬？"
        },
        {
          "type": "sound",
          "text": "音效：轻轻的脚步声从单采室方向传来"
        },
        {
          "type": "action",
          "text": "【中景】宿寒英从单采室方向走来。他在沈央身旁停下，低头看了他一眼——然后什么也没说，安静地在他旁边坐下。"
        },
        {
          "type": "action",
          "text": "【全景·侧面】两人并肩坐在台阶上，黄昏的暖光从窗口洒在他们身上。宿寒英的黑色衬衫和沈央的白色T恤，一明一暗，映在橘色光晕里。"
        },
        {
          "type": "sound",
          "text": "BGM：温柔舒缓的钢琴曲，如同黄昏的光"
        },
        {
          "type": "action",
          "text": "【中景】沉默持续了好几秒。沈央没有抬头，但他的肩膀慢慢放松了一些——旁边人的存在有种说不清的安定感。"
        },
        {
          "type": "dialogue",
          "character": "沈央",
          "emotion": "轻声、有点丧",
          "text": "我好像不太适合上综艺。"
        },
        {
          "type": "action",
          "text": "【近景】宿寒英没有立刻回答。他微微侧头，看着沈央低垂的侧脸。黄昏的光在他白皙的面庞上镀了一层暖色。"
        },
        {
          "type": "dialogue",
          "character": "宿寒英",
          "emotion": "平静温和",
          "text": "你比你想的有趣。"
        },
        {
          "type": "action",
          "text": "【特写】沈央的睫毛颤了一下，缓缓抬起头。黄昏逆光中，宿寒英的侧脸轮廓柔和，眼底映着窗外的晚霞。"
        },
        {
          "type": "action",
          "text": "【大特写】沈央的耳尖——在暖光的映照下，微微泛红。"
        },
        {
          "type": "inner_voice",
          "character": "沈央",
          "emotion": "心跳微乱",
          "text": "……明明不是什么了不起的话。可为什么，听到他这么说，居然觉得好像没那么糟了？"
        },
        {
          "type": "action",
          "text": "【中景】两人坐在黄昏的台阶上，没有再说话。光线一点一点暗下去，楼道里渐渐笼上傍晚的柔和阴影。"
        },
        {
          "type": "effect",
          "text": "【淡出】画面缓缓变暗。字幕：「待续」"
        }
      ]
    }
  ]
}
